import Foundation

/// Native implementation of HybridBenchmarkProtocol.
/// This file is yours to edit — the protocol is generated by `nitrogen generate`.
///
/// Kept minimal on purpose: this module measures the Swift dispatch tier.
/// Struct/record/stream benchmarks live in BenchmarkCpp (C++).
public class BenchmarkImpl: NSObject, HybridBenchmarkProtocol {

    public func add(a: Double, b: Double) -> Double {
        return a + b
    }

    public func addFast(a: Double, b: Double) -> Double {
        return a + b
    }

    public func getGreeting(name: String) -> String {
        return "Hello, \(name)!"
    }

    public func hashBuffer(data: Data, rounds: Int64) -> Int64 {
        // Reference workload: FNV-1a 64-bit — identical algorithm to the
        // MethodChannel handler (same language, different bridge) and to
        // src/nitro_workload.h. &* wraps mod 2^64, matching C uint64_t.
        var hash: UInt64 = 0xcbf29ce484222325
        data.withUnsafeBytes { (ptr: UnsafeRawBufferPointer) in
            let bytes = ptr.bindMemory(to: UInt8.self)
            for _ in 0..<rounds {
                for i in 0..<bytes.count {
                    hash ^= UInt64(bytes[i])
                    hash = hash &* 0x100000001b3
                }
            }
        }
        return Int64(bitPattern: hash)
    }

    public func sendLargeBuffer(buffer: Data) -> Int64 {
        var sum: UInt8 = 0
        // Access memory to prevent optimization
        buffer.withUnsafeBytes { ptr in
            let bytes = ptr.bindMemory(to: UInt8.self)
            for i in stride(from: 0, to: buffer.count, by: 4096) {
                sum = sum &+ bytes[i]
            }
        }
        return Int64(buffer.count)
    }
}
